array_filter(
			$addons,
			function ( $key ) use ( $deprecated ) {
				return ! in_array( $key, $deprecated );
			},
			ARRAY_FILTER_USE_KEY
		)

usort(
			$plugins_data,
			function ( $a, $b ) {
				if ( $a['installed'] !== $b['installed'] ) {
					return $a['installed'] ? -1 : 1; // Installed comes first.
				}

				// If both are installed, prioritize non-valid licenses.
				if ( $a['installed'] ) {
					$a_is_valid = ( isset( $a['status'] ) && 'valid' === $a['status'] );
					$b_is_valid = ( isset( $b['status'] ) && 'valid' === $b['status'] );

					if ( $a_is_valid !== $b_is_valid ) {
						return $a_is_valid ? 1 : -1;
					}
				}

				return 0;
			}
		)

printf(
		/* translators: %1$s is replaced with the opening link tag, %2$s is replaced with the closing link tag */
		esc_html__( 'You can add actions that will be fired on submission. For details and support check %1$sout our add-ons%2$s.', 'wpcf7-redirect' ),
		'<a href="' . esc_url( $addons_url ) . '" target="_blank">',
		'</a>'
	)

array_filter(
			$pages,
			function ( $page_data, $page_key ) use ( $product_pages ) {
				return in_array( $page_key, $product_pages, true ) &&
					   isset( $page_data['plugin']['status'] ) &&
					   $page_data['plugin']['status'] === 'not-installed';
			},
			ARRAY_FILTER_USE_BOTH
		)

array_filter(
					$plugins,
					function( $plugin ) {
						return ( is_object( $plugin ) && isset( $plugin->slug ) && $plugin->slug !== 'learning-management-system' ) ||
							( is_array( $plugin ) && isset( $plugin['slug'] ) && $plugin['slug'] !== 'learning-management-system' );
					}
				)

wp_remote_post(
				sprintf( '%slicense/%s/%s/%s', Product::API_URL, $action, rawurlencode( $this->product->get_name() ), $license ),
				array(
					'body'    => wp_json_encode(
						array(
							'url' => rawurlencode( home_url() ),
						)
					),
					'headers' => array(
						'Content-Type' => 'application/json',
					),
				)
			)

array_filter(
			self::$notifications,
			function ( $value ) use ( $notification ) {
				if ( isset( $value['id'] ) && isset( $notification['id'] ) && $value['id'] === $notification['id'] ) {
					return true;
				}

				return false;
			}
		)

